generated_oml:
// Physical sensing components
instance TemperatureSensor : DTDFVocab:SensingComponent [
    base:desc "Temperature sensor positioned inside the styrofoam incubator box"
    DTDFVocab:producedData TemperatureDataTransmitted
]

instance HumiditySensor : DTDFVocab:SensingComponent [
    base:desc "Humidity sensor positioned inside the styrofoam incubator box"
    DTDFVocab:producedData HumidityDataTransmitted
]

// Data transmitted from sensors
instance TemperatureDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TemperatureSensor
]

instance HumidityDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HumiditySensor
]

// Time‑series data stored for modelling
instance TemperatureTimeSeries : DTDFVocab:Data [
    base:desc "Time‑series temperature data collected from the incubator"
    DTDFVocab:inputTo PythonExecutionEnabler
    DTDFVocab:fromData TemperatureDataTransmitted
]

instance HumidityTimeSeries : DTDFVocab:Data [
    base:desc "Time‑series humidity data collected from the incubator"
    DTDFVocab:inputTo PythonExecutionEnabler
    DTDFVocab:fromData HumidityDataTransmitted
]

// Enablers orchestrating the Digital Twin
instance PythonExecutionEnabler : DTDFVocab:Enabler [
    base:desc "Python backend executing differential equations, optimizations, and control logic (scipy, numpy, matplotlib)"
    DTDFVocab:enables RealTimeMonitoringService , PredictiveSimulationService , FaultDetectionService , StateEstimationService , SupervisoryControlService , OptimizationService
]

instance RabbitMQBrokerEnabler : DTDFVocab:Enabler [
    base:desc "RabbitMQ messaging broker exchanging telemetry and command messages between the Raspberry Pi and the cloud simulation layer"
    DTDFVocab:enables RealTimeMonitoringService , SupervisoryControlService
]

// Digital Twin services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Real‑time monitoring of temperature and humidity against safety thresholds"
    DTDFVocab:provides RealTimeMonitoringInsight
]

instance PredictiveSimulationService : DTDFVocab:Service [
    base:desc "Predictive simulation of the incubator’s thermal behaviour using a differential equation model"
    DTDFVocab:provides PredictiveSimulationInsight
]

instance FaultDetectionService : DTDFVocab:Service [
    base:desc "Fault detection based on deviations between model predictions and sensor measurements"
    DTDFVocab:provides FaultDetectionInsight
]

instance StateEstimationService : DTDFVocab:Service [
    base:desc "State estimation of the incubator environment using Kalman‑filter‑style data fusion"
    DTDFVocab:provides StateEstimationInsight
]

instance SupervisoryControlService : DTDFVocab:Service [
    base:desc "Supervisory control issuing commands to actuators to maintain desired temperature and humidity"
    DTDFVocab:provides ControlHeatbedAction , ControlFanAction
]

instance OptimizationService : DTDFVocab:Service [
    base:desc "Optimization of heating element power to achieve target temperature while minimizing energy consumption"
    DTDFVocab:provides OptimizationRecommendationInsight
]

// Insights
instance RealTimeMonitoringInsight : DTDFVocab:Insight [
    base:desc "Insight showing temperature and humidity trends and highlighting any violations of safety limits"
]

instance PredictiveSimulationInsight : DTDFVocab:Insight [
    base:desc "Insight presenting predicted future temperature and humidity trajectories under current operating conditions"
]

instance FaultDetectionInsight : DTDFVocab:Insight [
    base:desc "Insight indicating detected faults such as sensor failure or actuator malfunction"
]

instance StateEstimationInsight : DTDFVocab:Insight [
    base:desc "Insight providing estimated internal states of the incubator system (e.g., air temperature distribution)"
]

instance OptimizationRecommendationInsight : DTDFVocab:Insight [
    base:desc "Insight recommending optimal heatbed power level to achieve target temperature with minimal energy use"
]

// Actions
instance ControlHeatbedAction : DTDFVocab:Action [
    base:desc "Command to adjust the heatbed element temperature setpoint"
    DTDFVocab:IsAutomatic false
]

instance ControlFanAction : DTDFVocab:Action [
    base:desc "Command to adjust the fan speed for air circulation"
    DTDFVocab:IsAutomatic false
]

// Physical actuators
instance HeatbedActuator : DTDFVocab:ActingComponent [
    base:desc "Heatbed element providing controlled temperature to the incubator enclosure"
]

instance FanActuator : DTDFVocab:ActingComponent [
    base:desc "Fan providing air circulation within the incubator enclosure"
]

// Physical components contained in the environment
instance StyrofoamBox : DTDFVocab:Component [
    base:desc "Styrofoam insulation box forming the incubator enclosure"
]

instance LabEnvironment : DTDFVocab:Environment [
    base:contains HeatbedActuator , FanActuator , StyrofoamBox
]
